// ── Search helper ─────────────────────────────────────────────────────────────
/** Levenshtein distance for fuzzy matching (short strings only) */
function levenshtein(a: string, b: string): number {
  if (a === b) return 0;
  if (a.length === 0) return b.length;
  if (b.length === 0) return a.length;
  const m: number[][] = Array.from({ length: a.length + 1 }, (_, i) =>
    Array.from({ length: b.length + 1 }, (_, j) => (i === 0 ? j : j === 0 ? i : 0))
  );
  for (let i = 1; i <= a.length; i++)
    for (let j = 1; j <= b.length; j++)
      m[i][j] = a[i-1] === b[j-1] ? m[i-1][j-1] : 1 + Math.min(m[i-1][j], m[i][j-1], m[i-1][j-1]);
  return m[a.length][b.length];
}

export function searchFacilities(query: string, limit = 12): PatientFacility[] {
  if (!query || query.trim().length < 2) {
    return PATIENT_FACILITIES
      .filter(f => f.priority <= 2 && f.type === "hospital")
      .sort((a, b) => a.priority - b.priority || a.name.localeCompare(b.name))
      .slice(0, limit);
  }

  const q = query.toLowerCase().trim();
  const tokens = q.split(/\s+/);

  const scored = PATIENT_FACILITIES.map(f => {
    const nameLower   = f.name.toLowerCase();
    const suburbLower = f.suburb.toLowerCase();
    const icaoLower   = (f.icao  ?? "").toLowerCase();
    const lhdLower    = (f.lhd   ?? "").toLowerCase();
    const haystack    = `${nameLower} ${suburbLower} ${f.state.toLowerCase()} ${icaoLower} ${lhdLower}`;
    let score = 0;

    if (icaoLower && icaoLower === q) score += 200;
    if (nameLower.startsWith(q)) score += 100;
    if (suburbLower.startsWith(q)) score += 80;
    if (nameLower.includes(q)) score += 60;
    if (suburbLower.includes(q)) score += 50;
    if (tokens.every(t => haystack.includes(t))) score += 40;
    tokens.forEach(t => { if (haystack.includes(t)) score += 10; });

    if (score === 0 && q.length >= 4) {
      const words = haystack.split(/\s+/);
      for (const token of tokens) {
        if (token.length < 4) continue;
        for (const word of words) {
          if (word.length < 3) continue;
          const dist = levenshtein(token, word.slice(0, token.length + 2));
          if (dist <= Math.floor(token.length / 4) + 1) { score += 8; break; }
        }
      }
    }

    if (f.type === "hospital") score += 3;
    else if (f.type === "nursing_home" || f.type === "aged_care") score += 1;
    score += Math.max(0, 5 - f.priority);

    return { f, score };
  });

  return scored
    .filter(s => s.score > 0)
    .sort((a, b) => b.score - a.score || a.f.name.localeCompare(b.f.name))
    .slice(0, limit)
    .map(s => s.f);
}

